const body = $json.body || $json;
if (!body.provider || !body.input) throw new Error('provider + input required');
const input = body.input;
const currency = input.currency || 'TWD';
const exchangeRate = Number(input.exchangeRate ?? 1);
if (currency !== 'TWD' && !(exchangeRate > 0)) {
  throw new Error('exchangeRate must be positive when currency != TWD');
}
if (currency === 'TWD' && exchangeRate !== 1) {
  throw new Error('exchangeRate must be 1 (or omitted) when currency = TWD');
}
if (!/^[A-Z]{3}$/.test(currency)) {
  throw new Error('currency must be ISO 4217 (3 uppercase letters)');
}
// MIG invariant: amount.totalAmount is TWD integer regardless of currency
const total = Number(input.amount?.totalAmount ?? 0);
if (!Number.isInteger(total) || total <= 0) {
  throw new Error('amount.totalAmount must be positive TWD integer (MIG invariant)');
}
return [{ json: {
  correlationId: `inv-fx-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  startedAt: new Date().toISOString(),
  provider: body.provider,
  input,
  fx: { currency, exchangeRate, twdTotal: total, originalApprox: currency === 'TWD' ? null : (total / exchangeRate).toFixed(2) }
}}];

const state = $('Stamp + validate FX').first().json;
const statusCode = Number($json.statusCode ?? 0);
const respBody = $json.body ?? $json;
const ok = statusCode >= 200 && statusCode < 300;
const unsupported = statusCode === 400 && respBody?.error?.code === 'UNSUPPORTED';
return [{ json: {
  ...state,
  statusCode,
  ok,
  unsupported,
  status: ok ? 'issued' : (unsupported ? 'unsupported-by-provider' : 'failed'),
  invoiceNumber: ok ? respBody?.result?.invoiceNumber : null,
  errorCode: respBody?.error?.code ?? null,
  errorMessage: respBody?.error?.message ?? null,
  appliedAt: new Date().toISOString()
} }];
